class LmdbProjectionPushdownOptimizerTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void pushesProjectionThroughFilterAndRetainsFilterVars() {
		StatementPattern pattern = statementPattern("s", "p", "o");
		Filter filter = new Filter(pattern,
				new Compare(new Var("o"), new ValueConstant(VF.createLiteral("Ada")), Compare.CompareOp.EQ));
		QueryRoot root = new QueryRoot(project(filter, "s"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "s");
		Filter pushedFilter = assertInstanceOf(Filter.class, outer.getArg(), () -> root.getArg().toString());
		assertProjection(pushedFilter.getArg(), "s", "o");
	}

	@Test
	void pushesProjectionIntoJoinSidesAndRetainsSharedVars() {
		StatementPattern left = statementPattern("person", "type", "type");
		StatementPattern right = statementPattern("person", "name", "name");
		QueryRoot root = new QueryRoot(project(new Join(left, right), "name"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "name");
		Join join = assertInstanceOf(Join.class, outer.getArg(), () -> root.getArg().toString());
		assertProjection(join.getLeftArg(), "person");
		assertProjection(join.getRightArg(), "person", "name");
	}

	@Test
	void pushesProjectionIntoCompatibleUnionBranches() {
		StatementPattern left = statementPattern("entity", "name", "label");
		StatementPattern right = statementPattern("entity", "alias", "label");
		QueryRoot root = new QueryRoot(project(new Union(left, right), "entity"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "entity");
		Union union = assertInstanceOf(Union.class, outer.getArg(), () -> root.getArg().toString());
		assertProjection(union.getLeftArg(), "entity");
		assertProjection(union.getRightArg(), "entity");
	}

	@Test
	void pushesProjectionIntoMinusAndRetainsCompatibilityVars() {
		StatementPattern left = statementPattern("person", "type", "type");
		StatementPattern right = statementPattern("person", "blocked", "blocked");
		QueryRoot root = new QueryRoot(project(new Difference(left, right), "type"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "type");
		Difference difference = assertInstanceOf(Difference.class, outer.getArg(), () -> root.getArg().toString());
		assertProjection(difference.getLeftArg(), "person", "type");
		assertProjection(difference.getRightArg(), "person");
	}

	@Test
	void pushesProjectionIntoUnconditionedLeftJoin() {
		StatementPattern left = statementPattern("person", "type", "type");
		StatementPattern right = statementPattern("person", "name", "name");
		QueryRoot root = new QueryRoot(project(new LeftJoin(left, right), "type"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "type");
		LeftJoin leftJoin = assertInstanceOf(LeftJoin.class, outer.getArg(), () -> root.getArg().toString());
		assertProjection(leftJoin.getLeftArg(), "person", "type");
		assertProjection(leftJoin.getRightArg(), "person");
	}

	@Test
	void pushedLeftJoinBranchProjectionsAreTransparentAndDoNotForceHashJoin() {
		StatementPattern left = statementPattern("person", "type", "type");
		StatementPattern right = statementPattern("person", "name", "name");
		QueryRoot root = new QueryRoot(project(new LeftJoin(left, right), "name"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "name");
		LeftJoin leftJoin = assertInstanceOf(LeftJoin.class, outer.getArg(), () -> root.getArg().toString());
		Projection leftProjection = assertProjection(leftJoin.getLeftArg(), "person");
		Projection rightProjection = assertProjection(leftJoin.getRightArg(), "person", "name");

		assertFalse(leftProjection.isSubquery(), () -> "optimizer-created left projection must be transparent:\n"
				+ root);
		assertFalse(rightProjection.isSubquery(), () -> "optimizer-created right projection must be transparent:\n"
				+ root);
		assertFalse(TupleExprs.containsSubquery(leftJoin.getRightArg()),
				() -> "transparent OPTIONAL right projection must not force HashJoinIteration:\n" + root);
	}

	@Test
	void skipsConditionedLeftJoin() {
		StatementPattern left = statementPattern("person", "type", "type");
		StatementPattern right = statementPattern("person", "name", "name");
		Compare condition = new Compare(new Var("name"), new ValueConstant(VF.createLiteral("Ada")),
				Compare.CompareOp.EQ);
		QueryRoot root = new QueryRoot(project(new LeftJoin(left, right, condition), "type"));

		optimize(root);

		Projection outer = assertProjection(root.getArg(), "type");
		LeftJoin leftJoin = assertInstanceOf(LeftJoin.class, outer.getArg(), () -> root.getArg().toString());
		assertInstanceOf(StatementPattern.class, leftJoin.getLeftArg(), () -> root.getArg().toString());
		assertInstanceOf(StatementPattern.class, leftJoin.getRightArg(), () -> root.getArg().toString());
	}

	@Test
	void mergesNestedIdentityProjections() {
		QueryRoot root = new QueryRoot(project(project(statementPattern("s", "p", "o"), "s", "o"), "s"));

		optimize(root);

		Projection projection = assertProjection(root.getArg(), "s");
		assertInstanceOf(StatementPattern.class, projection.getArg(), () -> root.getArg().toString());
	}

	@Test
	void skipsAliasedProjection() {
		QueryRoot root = new QueryRoot(new Projection(statementPattern("s", "p", "o"),
				new ProjectionElemList(new ProjectionElem("o", "label"))));

		optimize(root);

		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.getArg().toString());
		assertInstanceOf(StatementPattern.class, projection.getArg(), () -> root.getArg().toString());
		assertEquals("label",
				projection.getProjectionElemList().getElements().getFirst().getProjectionAlias().orElseThrow());
	}

	@Test
	void skipsScopeChangingExtensionAndGroup() {
		Extension extension = new Extension(statementPattern("s", "p", "o"), new ExtensionElem(new Var("o"),
				"derived"));
		Group group = new Group(statementPattern("s", "q", "value"));
		group.addGroupBindingName("s");
		group.addGroupElement(new GroupElem("valueCount", new Count(new Var("value"))));
		QueryRoot extensionRoot = new QueryRoot(project(extension, "derived"));
		QueryRoot groupRoot = new QueryRoot(project(group, "s"));

		optimize(extensionRoot);
		optimize(groupRoot);

		assertInstanceOf(Extension.class, assertProjection(extensionRoot.getArg(), "derived").getArg(),
				() -> extensionRoot.getArg().toString());
		assertInstanceOf(Group.class, assertProjection(groupRoot.getArg(), "s").getArg(),
				() -> groupRoot.getArg().toString());
	}

	private static void optimize(TupleExpr tupleExpr) {
		new LmdbProjectionPushdownOptimizer().optimize(tupleExpr, null, EmptyBindingSet.getInstance());
	}

	private static StatementPattern statementPattern(String subjectName, String predicateName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var(predicateName, VF.createIRI("urn:" + predicateName)),
				new Var(objectName));
	}

	private static Projection project(TupleExpr arg, String... names) {
		ProjectionElemList projectionElemList = new ProjectionElemList();
		for (String name : names) {
			projectionElemList.addElement(new ProjectionElem(name));
		}
		return new Projection(arg, projectionElemList);
	}

	private static Projection assertProjection(TupleExpr tupleExpr, String... names) {
		Projection projection = assertInstanceOf(Projection.class, tupleExpr, () -> tupleExpr.toString());
		assertIterableEquals(List.of(names), projectionNames(projection), () -> projection.toString());
		return projection;
	}

	private static List<String> projectionNames(Projection projection) {
		return projection.getProjectionElemList()
				.getElements()
				.stream()
				.map(ProjectionElem::getName)
				.toList();
	}
}
